// AUTO-GENERATED DRAFT SCREEN: CryptoPortfolioDashboard
import React from 'react';
import { useQuery } from '@tanstack/react-query'; // Assuming tRPC integrates with react-query
import { Card, CardContent, CardHeader, CardTitle } from '@/components/ui/card';
import { Skeleton } from '@/components/ui/skeleton';
import { Alert, AlertDescription, AlertTitle } from '@/components/ui/alert';
import { SunIcon, MoonIcon } from 'lucide-react';
import { Button } from '@/components/ui/button';

// Placeholder for tRPC client and types
// In a real application, these would be generated by tRPC
interface PortfolioItem {
  id: string;
  name: string;
  symbol: string;
  amount: number;
  valueUSD: number;
}

interface PortfolioData {
  totalValueUSD: number;
  items: PortfolioItem[];
}

// Mock tRPC hook for demonstration
const trpc = {
  portfolio: {
    getDashboardData: {
      useQuery: () => {
        const [data, setData] = React.useState<PortfolioData | undefined>(undefined);
        const [isLoading, setIsLoading] = React.useState(true);
        const [isError, setIsError] = React.useState(false);

        React.useEffect(() => {
          const fetchData = async () => {
            setIsLoading(true);
            setIsError(false);
            try {
              // Simulate API call
              await new Promise(resolve => setTimeout(resolve, 1500));
              const mockData: PortfolioData = {
                totalValueUSD: 12345.67,
                items: [
                  { id: '1', name: 'Bitcoin', symbol: 'BTC', amount: 0.5, valueUSD: 15000 },
                  { id: '2', name: 'Ethereum', symbol: 'ETH', amount: 3, valueUSD: 9000 },
                  { id: '3', name: 'SKYCOIN', symbol: 'SKY', amount: 1000, valueUSD: 4444 },
                ],
              };
              setData(mockData);
            } catch (error) {
              setIsError(true);
            } finally {
              setIsLoading(false);
            }
          };
          fetchData();
        }, []);

        return { data, isLoading, isError };
      },
    },
  },
};

const CryptoPortfolioDashboard: React.FC = () => {
  const { data, isLoading, isError } = trpc.portfolio.getDashboardData.useQuery();
  const [isDarkTheme, setIsDarkTheme] = React.useState(false);

  React.useEffect(() => {
    document.documentElement.classList.toggle('dark', isDarkTheme);
  }, [isDarkTheme]);

  const toggleTheme = () => {
    setIsDarkTheme(prev => !prev);
  };

  if (isLoading) {
    return (
      <div className="p-4 space-y-4">
        <Skeleton className="h-10 w-1/2" />
        <Skeleton className="h-24 w-full" />
        <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-4">
          <Skeleton className="h-32 w-full" />
          <Skeleton className="h-32 w-full" />
          <Skeleton className="h-32 w-full" />
        </div>
      </div>
    );
  }

  if (isError) {
    return (
      <div className="p-4">
        <Alert variant="destructive">
          <AlertTitle>Error</AlertTitle>
          <AlertDescription>Failed to load portfolio data. Please try again later.</AlertDescription>
        </Alert>
      </div>
    );
  }

  return (
    <div className="min-h-screen bg-background text-foreground p-4">
      <div className="flex justify-between items-center mb-6">
        <h1 className="text-3xl font-bold">Crypto Portfolio Dashboard</h1>
        <Button variant="outline" size="icon" onClick={toggleTheme} aria-label="Toggle theme">
          {isDarkTheme ? <SunIcon className="h-5 w-5" /> : <MoonIcon className="h-5 w-5" />}
        </Button>
      </div>

      <Card className="mb-6">
        <CardHeader>
          <CardTitle>Total Portfolio Value</CardTitle>
        </CardHeader>
        <CardContent>
          <p className="text-4xl font-extrabold">${data?.totalValueUSD.toLocaleString('en-US', { minimumFractionDigits: 2, maximumFractionDigits: 2 })}</p>
        </CardContent>
      </Card>

      <h2 className="text-2xl font-semibold mb-4">Your Assets</h2>
      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-4">
        {data?.items.map(item => (
          <Card key={item.id}>
            <CardHeader>
              <CardTitle className="flex items-center justify-between">
                <span>{item.name} ({item.symbol})</span>
                <span className="text-sm text-muted-foreground">Amount: {item.amount}</span>
              </CardTitle>
            </CardHeader>
            <CardContent>
              <p className="text-2xl font-bold">${item.valueUSD.toLocaleString('en-US', { minimumFractionDigits: 2, maximumFractionDigits: 2 })}</p>
            </CardContent>
          </Card>
        ))}
      </div>
    </div>
  );
};

export default CryptoPortfolioDashboard;